int main_test() {
    int size;
    std::cin >> size;

    if (size <= 0) {
        std::cout << "Array size must be positive." << std::endl;
        return 1;
    }

    int* arr = new int[size];

    for (int i = 0; i < size; ++i) {
        arr[i] = i + 1; // This is the logical error
    }

    std::cout << "Array elements: ";
    for (int i = 0; i < size; ++i) {
        std::cout << arr[i] << " ";
    }
    std::cout << std::endl;

    delete[] arr;
    arr = nullptr;

    return 0;
}

int main() {
    return main_test();
}
